import{_ as o,o as t,c as d,a3 as c}from"./chunks/framework.BTFg6ESq.js";const u=JSON.parse('{"title":"移除 stream-monaco 方案","description":"","frontmatter":{},"headers":[],"relativePath":"Plan/stream-monaco-removal-plan.md","filePath":"Plan/stream-monaco-removal-plan.md","lastUpdated":1781266243000}'),i={name:"Plan/stream-monaco-removal-plan.md"};function a(r,e,n,s,l,p){return t(),d("div",null,[...e[0]||(e[0]=[c(`<h1 id="移除-stream-monaco-方案" tabindex="-1">移除 stream-monaco 方案 <a class="header-anchor" href="#移除-stream-monaco-方案" aria-label="Permalink to &quot;移除 stream-monaco 方案&quot;">​</a></h1><blockquote><p>日期:2026-06-12 性质:修改方案(已实施),是 <a href="./app-startup-optimization-investigation">app-startup-optimization-investigation.md</a> 中 P0-2 的升级形态——从&quot;懒加载化&quot;升级为&quot;整体移除&quot; 动机:实测 CodeMirror 作为消息代码块显示引擎的本底性能大幅优于 Monaco;且 stream-monaco 是启动关键路径上单笔最大的静态负债(3.63 MB ESM Monaco + Shiki 全家桶)</p></blockquote><h2 id="结论先行" tabindex="-1">结论先行 <a class="header-anchor" href="#结论先行" aria-label="Permalink to &quot;结论先行&quot;">​</a></h2><p><strong>移除可行,改动面小,无数据迁移。</strong> 全仓库审计结果:</p><h2 id="实施记录" tabindex="-1">实施记录 <a class="header-anchor" href="#实施记录" aria-label="Permalink to &quot;实施记录&quot;">​</a></h2><h3 id="_2026-06-12-落地实施" tabindex="-1">2026-06-12 落地实施 <a class="header-anchor" href="#_2026-06-12-落地实施" aria-label="Permalink to &quot;2026-06-12 落地实施&quot;">​</a></h3><p>已按本方案完成 <code>stream-monaco</code> 消息代码块路径移除:</p><ul><li>删除 <code>src/utils/monacoShikiSetup.ts</code> 与 <code>src/tools/rich-text-renderer/components/nodes/code-block/MonacoSourceViewer.vue</code>;</li><li><code>CodeBlockNode.vue</code> 固定渲染 <code>CodeMirrorSourceViewer</code>;</li><li>移除 <code>codeEditorEngine</code> 设置项、类型字段、默认值、<code>RichTextRenderer</code> prop/context、llm-chat 透传绑定和测试器引擎选择器;</li><li><code>appInitStore.ts</code> 不再调度 Monaco/Shiki 主题初始化;</li><li><code>package.json</code> 删除 <code>stream-monaco</code>、<code>shiki</code> 两个直接依赖,并通过 <code>bun install</code> 刷新 <code>bun.lock</code>;</li><li><code>codeLanguages.ts</code> 补齐 <code>c</code>、<code>toml</code>、<code>lua</code>、<code>powershell</code> 映射,并额外补了聊天代码块常见的 <code>diff</code> 与 <code>ini/properties</code>;</li><li>同步更新 rich-text-renderer 架构文档、llm-chat 架构文档、用户渲染设置文档和相关性能调查文档。</li></ul><p>与原计划的差异:</p><ul><li><p><code>appInitStore.ts</code> 在前序启动优化中已经改成首帧后后台任务,本次实际删除的是后台 <code>initMonacoShikiThemes()</code> 调度,不是计划中旧版的首帧前 <code>await</code> 步骤;</p></li><li><p>额外清理了 <code>rich-text-renderer</code> 测试 store 中的 <code>codeEditorEngine</code> 持久化字段,避免测试器配置继续保存一个永远不生效的选项;</p></li><li><p>语言映射除计划内 4 个外,同步加入 <code>diff</code> 与 <code>ini/properties</code>;</p></li><li><p><code>bun.lock</code> 中仍保留 VitePress 间接依赖的 <code>shiki</code> 子树,但项目直接依赖和 <code>stream-monaco</code> 子树已移除。</p></li><li><p>stream-monaco 只有 <strong>2 个消费方</strong>:<code>src/utils/monacoShikiSetup.ts:14</code>(静态导入,启动链元凶)和 <code>src/tools/rich-text-renderer/components/nodes/code-block/MonacoSourceViewer.vue:347</code>(已是动态导入);</p></li><li><p>消息代码块的<strong>默认引擎已经是 CodeMirror</strong>(<code>llm-chat/types/settings.ts:363</code>、<code>RichTextRenderer.vue:153</code>),Monaco viewer 只是遗留可选路径,<code>CodeMirrorSourceViewer.vue</code> 功能完备(懒初始化、主题、流式更新、折叠/行号/换行/字号);</p></li><li><p><code>shiki</code> 依赖<strong>没有任何其他直接消费方</strong>,可连带移除;</p></li><li><p><code>monaco-editor</code> 包<strong>必须保留</strong>(RichCodeEditor 的 @guolao AMD 栈 + 4 处懒加载视图中的 ESM 用法);</p></li><li><p>移动端零涉及。</p></li></ul><p>收益:</p><table tabindex="0"><thead><tr><th>维度</th><th>效果</th></tr></thead><tbody><tr><td>启动载荷</td><td>入口图甩掉 <code>editor.api2</code> 3.63 MB + shiki 核心/wasm/语法 chunk(17.5 MiB 起步直接 -3.7 MB 左右)</td></tr><tr><td><code>initMainApp</code></td><td>删除 30% 那步的 <code>await initMonacoShikiThemes()</code>,实测 135–190ms;<code>initDetachedApp</code> 同样受益</td></tr><tr><td>架构债</td><td>&quot;Shiki 主题欺骗&quot; hack(<code>monacoShikiSetup.ts</code> 全文件)连根消失——它存在的唯一理由就是 stream-monaco 的 <code>shikiToMonaco</code> 会全局劫持 <code>editor.setTheme</code></td></tr><tr><td>依赖</td><td>移除 <code>stream-monaco</code>、<code>shiki</code> 两个直接依赖(及 alien-signals 等传递依赖)</td></tr></tbody></table><p>唯一功能回退:高亮引擎从 Shiki(TextMate 级)换为 Lezer/legacy-modes,现有语言映射有几个缺口(<code>c</code>/<code>toml</code>/<code>lua</code>/<code>powershell</code>),<code>@codemirror/legacy-modes</code> 全有现成 mode,本方案一并补上。</p><hr><h2 id="一、现状盘点" tabindex="-1">一、现状盘点 <a class="header-anchor" href="#一、现状盘点" aria-label="Permalink to &quot;一、现状盘点&quot;">​</a></h2><h3 id="_1-1-stream-monaco-的两条消费链" tabindex="-1">1.1 stream-monaco 的两条消费链 <a class="header-anchor" href="#_1-1-stream-monaco-的两条消费链" aria-label="Permalink to &quot;1.1 stream-monaco 的两条消费链&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 启动链(静态,问题所在):</span></span>
<span class="line"><span>   main.ts → App.vue → appInitStore.ts:13</span></span>
<span class="line"><span>     → monacoShikiSetup.ts:14  import { registerMonacoThemes } from &quot;stream-monaco&quot;</span></span>
<span class="line"><span>       → stream-monaco 顶层 import * as monaco from &quot;monaco-editor&quot; + import { createHighlighter } from &quot;shiki&quot;</span></span>
<span class="line"><span>   运行时:initMainApp 30%(appInitStore.ts:69-70)与 initDetachedApp 35%(appInitStore.ts:139-141)</span></span>
<span class="line"><span>   都 await initMonacoShikiThemes() → 注册 vs-dark/vs 假主题 + 23 种语言语法预热</span></span>
<span class="line"><span></span></span>
<span class="line"><span>② 渲染链(动态,本身无启动问题):</span></span>
<span class="line"><span>   CodeBlockNode.vue:45-64 按 context.codeEditorEngine 分支</span></span>
<span class="line"><span>     ├─ engine !== &#39;codemirror&#39; → MonacoSourceViewer.vue(内部 await import(&quot;stream-monaco&quot;))</span></span>
<span class="line"><span>     └─ engine === &#39;codemirror&#39; → CodeMirrorSourceViewer.vue(默认路径)</span></span></code></pre></div><h3 id="_1-2-codeeditorengine-设置的完整管线" tabindex="-1">1.2 <code>codeEditorEngine</code> 设置的完整管线 <a class="header-anchor" href="#_1-2-codeeditorengine-设置的完整管线" aria-label="Permalink to &quot;1.2 \`codeEditorEngine\` 设置的完整管线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层</th><th>位置</th></tr></thead><tbody><tr><td>类型定义</td><td><code>llm-chat/types/settings.ts:191</code>(<code>&quot;monaco&quot; | &quot;codemirror&quot;</code>),默认值 <code>:363</code>(<code>&quot;codemirror&quot;</code>)</td></tr><tr><td>设置 UI</td><td><code>llm-chat/components/settings/settingsConfig.ts:579-593</code>(ElSelect,两个选项)</td></tr><tr><td>透传(llm-chat)</td><td><code>MessageContent.vue:924,1083,1164</code>、<code>CompressionMessage.vue:358</code>、<code>ToolCallMessage.vue:1137</code>、<code>PresetMessageEditor.vue:274</code> 共 6 处 <code>:code-editor-engine=&quot;settings.uiPreferences.codeEditorEngine&quot;</code></td></tr><tr><td>渲染器 props/context</td><td><code>RichTextRenderer.vue:135,153,336</code>;<code>rich-text-renderer/types.ts:787,887</code></td></tr><tr><td>测试器</td><td><code>RichTextRendererTester.vue:187,259,431</code>、<code>TesterConfigSidebar.vue:122,556</code>(本地引擎切换器)</td></tr><tr><td>消费</td><td><code>CodeBlockNode.vue:46</code>(唯一真正读取处)</td></tr></tbody></table><h3 id="_1-3-monaco-editor-的其余消费方-移除后保留-不受影响" tabindex="-1">1.3 monaco-editor 的其余消费方(移除后保留,不受影响) <a class="header-anchor" href="#_1-3-monaco-editor-的其余消费方-移除后保留-不受影响" aria-label="Permalink to &quot;1.3 monaco-editor 的其余消费方(移除后保留,不受影响)&quot;">​</a></h3><ul><li><strong>AMD 栈</strong>(<code>@tomjs/vite-plugin-monaco-editor</code> 注入 + <code>@guolao/vue-monaco-editor</code>):<code>RichCodeEditor.vue</code>、<code>FilePreview.vue</code>、<code>useTextDiff.ts</code> 等——与本方案无关,见调查报告 P2-8;</li><li><strong>ESM 值导入</strong>(均在懒加载工具视图 chunk 内,不进入口):<code>PresetMessageEditor.vue:326</code>、<code>QuickActionDetail.vue:27</code>、<code>web-canvas/CanvasMonacoEditor.vue:3</code>、<code>web-canvas/MonacoModelManager.ts:1</code>;</li><li><strong>纯类型导入</strong>(编译期擦除):<code>RichCodeEditor.vue:52</code>、<code>FilePreview.vue:77</code>、<code>useTextDiff.ts:2</code>。</li></ul><p>已验证兼容性:ESM 消费方使用内置主题名(<code>CanvasMonacoEditor.vue:21</code>:<code>isDark ? &quot;vs-dark&quot; : &quot;vs&quot;</code>)。移除 stream-monaco 后 <code>shikiToMonaco</code> 劫持不再安装,内置主题名<strong>恢复原生可用</strong>,正是 <code>monacoShikiSetup</code> 当初要绕的坑自行消失。</p><h2 id="二、改动清单" tabindex="-1">二、改动清单 <a class="header-anchor" href="#二、改动清单" aria-label="Permalink to &quot;二、改动清单&quot;">​</a></h2><h3 id="_2-1-删除文件" tabindex="-1">2.1 删除文件 <a class="header-anchor" href="#_2-1-删除文件" aria-label="Permalink to &quot;2.1 删除文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>说明</th></tr></thead><tbody><tr><td><code>src/utils/monacoShikiSetup.ts</code></td><td>整文件删除(<code>initMonacoShikiThemes</code>/<code>isMonacoShikiReady</code> 仅 appInitStore 消费)</td></tr><tr><td><code>src/tools/rich-text-renderer/components/nodes/code-block/MonacoSourceViewer.vue</code></td><td>整文件删除</td></tr></tbody></table><p>注:<code>MonacoSourceViewer</code> 里的 <code>ensureMonacoPassiveTouchListeners</code> 全局补丁(<code>:92-124</code>)随之消失。它按 <code>.closest(&quot;.monaco-editor&quot;)</code> 匹配所有 Monaco 实例,但只在消息代码块初始化时才安装——未渲染过代码块的会话里 RichCodeEditor 本就运行在无补丁状态,故不构成回退;若后续 AMD Monaco 出现 touchstart 告警,再在 RichCodeEditor 侧按需恢复。</p><h3 id="_2-2-appinitstore-ts" tabindex="-1">2.2 <code>appInitStore.ts</code> <a class="header-anchor" href="#_2-2-appinitstore-ts" aria-label="Permalink to &quot;2.2 \`appInitStore.ts\`&quot;">​</a></h3><ul><li>删除 <code>:13</code> 的 <code>import { initMonacoShikiThemes } from &quot;@/utils/monacoShikiSetup&quot;</code>;</li><li><code>initMainApp</code>:删除 <code>:68-70</code>(30% &quot;初始化编辑器主题&quot; 一步),后续 setProgress 百分比顺延微调;</li><li><code>initDetachedApp</code>:删除 <code>:139-141</code>(35% 同名步骤)。</li></ul><h3 id="_2-3-codeblocknode-vue-简化" tabindex="-1">2.3 <code>CodeBlockNode.vue</code> 简化 <a class="header-anchor" href="#_2-3-codeblocknode-vue-简化" aria-label="Permalink to &quot;2.3 \`CodeBlockNode.vue\` 简化&quot;">​</a></h3><ul><li>模板 <code>:43-66</code>:删除双引擎分支,固定渲染 <code>CodeMirrorSourceViewer</code>;</li><li>删除 <code>:120</code> 的 <code>import MonacoSourceViewer</code>;</li><li><code>:46</code> 不再读取 <code>context?.codeEditorEngine</code>。</li></ul><h3 id="_2-4-codeeditorengine-设置退役" tabindex="-1">2.4 <code>codeEditorEngine</code> 设置退役 <a class="header-anchor" href="#_2-4-codeeditorengine-设置退役" aria-label="Permalink to &quot;2.4 \`codeEditorEngine\` 设置退役&quot;">​</a></h3><p>采用<strong>移除管线、容忍存量值</strong>策略(避免给老配置写迁移):</p><ul><li><code>types/settings.ts:191</code> 类型字段与 <code>:363</code> 默认值:删除字段;llm-chat 设置加载对多余键是宽容合并,存量 <code>uiPreferences.codeEditorEngine: &quot;monaco&quot;</code> 残留在用户 JSON 中无害,可不清理;</li><li><code>settingsConfig.ts:579-593</code>:删除该设置项;</li><li>6 处 llm-chat 透传绑定、<code>RichTextRenderer.vue</code> 的 prop/默认值/context 注入、<code>types.ts</code> 两处接口字段:全部删除;</li><li>测试器(<code>RichTextRendererTester.vue</code>、<code>TesterConfigSidebar.vue:122</code> 的切换器):删除引擎选择器与对应 ref。</li></ul><blockquote><p>备选方案(若想保守):保留类型与设置键,仅把 <code>CodeBlockNode</code> 改为无视该值。不推荐——会留下一个永远不生效的设置项 UI。</p></blockquote><h3 id="_2-5-语言映射补缺-src-utils-codelanguages-ts" tabindex="-1">2.5 语言映射补缺(<code>src/utils/codeLanguages.ts</code>) <a class="header-anchor" href="#_2-5-语言映射补缺-src-utils-codelanguages-ts" aria-label="Permalink to &quot;2.5 语言映射补缺(\`src/utils/codeLanguages.ts\`)&quot;">​</a></h3><p>为对齐原 Shiki 预热清单(<code>monacoShikiSetup.ts:28-52</code> 的 23 种语言),补 4 个映射,全部走 <code>@codemirror/legacy-modes</code>(已确认 mode 文件存在):</p><table tabindex="0"><thead><tr><th>语言</th><th>实现</th></tr></thead><tbody><tr><td><code>c</code></td><td><code>mode/clike</code> 的 <code>c</code>(注意:现有 <code>cpp</code> 条目别名只有 <code>[&quot;cpp&quot;,&quot;cxx&quot;]</code>,<code>c</code> 目前静默回退纯文本)</td></tr><tr><td><code>toml</code></td><td><code>mode/toml</code></td></tr><tr><td><code>lua</code></td><td><code>mode/lua</code></td></tr><tr><td><code>powershell</code>(别名 <code>ps1</code>/<code>pwsh</code>)</td><td><code>mode/powershell</code></td></tr></tbody></table><p>可选加分项:<code>diff</code>(<code>mode/diff</code>)、<code>ini/properties</code>(<code>mode/properties</code>)——聊天场景常见。</p><h3 id="_2-6-依赖与配置清理" tabindex="-1">2.6 依赖与配置清理 <a class="header-anchor" href="#_2-6-依赖与配置清理" aria-label="Permalink to &quot;2.6 依赖与配置清理&quot;">​</a></h3><ul><li><code>package.json</code>:删除 <code>stream-monaco</code>(:172)、<code>shiki</code>(:170),<code>bun install</code> 刷新 lockfile;</li><li><code>monaco-editor</code>(:162)、<code>@guolao/vue-monaco-editor</code>、<code>@tomjs/vite-plugin-monaco-editor</code>、全部 <code>@codemirror/*</code>、<code>@uiw/codemirror-theme-vscode</code>:保留;</li><li><code>vite.config.ts</code> 不动(monaco-i18n NLS 劫持、<code>optimizeDeps.exclude: [&quot;monaco-editor&quot;]</code> 服务于保留的 AMD/ESM Monaco)。</li></ul><h3 id="_2-7-文档同步" tabindex="-1">2.7 文档同步 <a class="header-anchor" href="#_2-7-文档同步" aria-label="Permalink to &quot;2.7 文档同步&quot;">​</a></h3><ul><li><code>rich-text-renderer/ARCHITECTURE.md</code>、<code>llm-chat/docs/architecture/composables-reference.md</code>:删去 MonacoSourceViewer/双引擎描述;</li><li><code>docs/Plan/app-startup-optimization-investigation.md</code> P0-2:标注&quot;已升级为移除方案,见本文档&quot;;</li><li><code>rich-text-renderer/docs/Plan/performance-optimization-investigation.md</code> 中涉及 stream-monaco 的条目如有,加一行落地说明;</li><li>用户文档 <code>docs/user-guide/tools/llm-chat/settings/rendering.md</code> 若描述了引擎选择,同步删除。</li></ul><h3 id="_2-8-顺手项-可选-不阻塞" tabindex="-1">2.8 顺手项(可选,不阻塞) <a class="header-anchor" href="#_2-8-顺手项-可选-不阻塞" aria-label="Permalink to &quot;2.8 顺手项(可选,不阻塞)&quot;">​</a></h3><ul><li><code>PreCodeNode.vue</code> 的 <code>theme=&quot;monaco&quot;</code> 变体样式成为死代码,可清理;</li><li><code>rich-text-renderer</code> store 的 <code>debugPreFallback</code> 仍被 CodeMirror viewer 使用,保留。</li></ul><h2 id="三、风险与边界" tabindex="-1">三、风险与边界 <a class="header-anchor" href="#三、风险与边界" aria-label="Permalink to &quot;三、风险与边界&quot;">​</a></h2><ol><li><strong>高亮保真度</strong>:Lezer/legacy-modes 的着色细腻度低于 Shiki(TextMate)。考虑到消息代码块是只读展示、用户已实测接受 CodeMirror 观感,并且默认引擎本就是 CM(绝大多数用户当前看到的就是 CM 效果),风险可控。</li><li><strong>流式更新方式</strong>:CM viewer 是全文 <code>dispatch</code> 替换(<code>CodeMirrorSourceViewer.vue:201-217</code>)而非 stream-monaco 的增量 applyEdits;实测性能反而更好,代码块量级下无压力。</li><li><strong>存量设置值</strong>:选了 &quot;monaco&quot; 的用户静默回到 CodeMirror,符合&quot;该选项本就标注 CM 更快&quot;的语义,无需提示。</li><li><strong>明确不在本方案范围</strong>(避免误解为已解决): <ul><li>AMD Monaco 的 head 同步脚本、309KB 阻塞 CSS、<code>editor.main.nls.js</code> 404(调查报告 P2-8);</li><li>codemirror(vendor-editor 1.23MB)经 plugin-ui eager glob 仍在入口(P0-1);</li><li>其余启动项(P1-5/P1-6 等)。</li></ul></li></ol><h2 id="四、实施顺序与验证" tabindex="-1">四、实施顺序与验证 <a class="header-anchor" href="#四、实施顺序与验证" aria-label="Permalink to &quot;四、实施顺序与验证&quot;">​</a></h2><p>建议单 PR,提交粒度:</p><ol><li>补语言映射(2.5)——独立可合,先行;</li><li>删 MonacoSourceViewer + CodeBlockNode 简化 + 设置管线退役(2.1/2.3/2.4);</li><li>删 monacoShikiSetup + appInitStore 两处调用(2.1/2.2);</li><li>依赖清理 + 文档同步(2.6/2.7)。</li></ol><p>验证:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:tsc</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 类型检查:确认无残留引用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:run</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 单测回归</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 产物验证(下一步)</span></span></code></pre></div><p>产物断言(对照调查报告附录的统计脚本):</p><ul><li><code>dist/index.html</code> 的 modulepreload 列表中 <strong><code>editor.api2-*.js</code> 消失</strong>,启动资源总量较 18,363,590 B 下降 ≥ 3.5 MB;</li><li><code>dist/assets</code> 中不再出现 shiki 语法/wasm chunk(搜 <code>oniguruma</code>/<code>textmate</code> 关键字);</li><li><code>vendor-vue</code> 体积显著回落(其中误并的 Shiki vue 系语法随移除消失——manualChunks 修复前的额外红利)。</li></ul><p>运行态验证(<code>bun run t:d</code>):</p><ul><li>含多语言代码块(含 c/toml/lua/powershell)的会话正常高亮、流式渲染、折叠/换行/字号正常;</li><li>设置页不再出现&quot;代码编辑器引擎&quot;项,老配置启动无报错;</li><li>RichCodeEditor(如 llm-chat Agent 编辑器)、web-canvas Monaco 编辑器、text-diff 工具正常,主题随明暗切换正确(验证劫持消失后内置主题可用);</li><li>分离窗口打开 llm-chat,代码块渲染正常(<code>initDetachedApp</code> 路径)。</li></ul><p>回滚:无数据迁移、无格式变更,<code>git revert</code> 单 PR 即可完整回退。</p>`,56)])])}const m=o(i,[["render",a]]);export{u as __pageData,m as default};
